/**
 * @fileoverview Navbar view — DOM helper.
 * @module module/Navbar/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root) {
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    root.find('.' + CLS.SECTION).each(el => {
        PART.SECTION.apply(el);
    });
    root.find('.' + CLS.ITEM).each(el => {
        PART.ITEM.apply(el);
    });
    root.find('.' + CLS.LABEL).each(el => {
        PART.LABEL.apply(el);
    });
    root.find('.' + CLS.DIVIDER).each(el => {
        PART.DIVIDER.apply(el);
    });
    root.find('.' + CLS.SPACER).each(el => {
        PART.SPACER.apply(el);
    });

    return {};
}
