/**
 * @fileoverview Navbar component — modular entry point.
 *
 * The Navbar is a lightweight structural component. Most of its
 * styling comes from JIT classes applied via the definition.
 * Child elements (sections, items, dividers, spacers) are expected
 * to carry the appropriate CSS classes, either authored in HTML
 * or applied programmatically.
 *
 * @module module/Navbar
 */

import { default as razyui } from '../../index.js';
import { DEFAULTS, CLS } from './constants.js';
import { setupDOM } from './view.js';

const Navbar = class {
    #root   = null;
    #destroyed = false;
    #config = {};
    #eventAC     = new AbortController();

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Navbar: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        setupDOM(root);
        this.#init();
    }

    #init() {
        const sig = { signal: this.#eventAC.signal };
        this.#root[0].addEventListener('click', (e) => {
            const item = e.target.closest('.' + CLS.ITEM);
            if (!item || item.closest('.' + CLS.ROOT) !== this.#root[0]) return;
            this.#root.find('.' + CLS.ITEM + '.' + CLS.CURRENT).each(el => {
                el.classList.remove(CLS.CURRENT);
            });
            item.classList.add(CLS.CURRENT);
        }, sig);
    }

    get element() { return this.#root[0]; }

    getControl() {
        const self = this;
        return {
            get element() { return self.element; },
            destroy: () => self.destroy(),
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
    }
};

export default Navbar;
