/**
 * @fileoverview Navbar constants.
 * @module module/Navbar/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:    'navbar',
    SECTION: 'navbar-section',
    ITEM:    'navbar-item',
    LABEL:   'navbar-label',
    DIVIDER: 'navbar-divider',
    SPACER:  'navbar-spacer',
    CURRENT: 'is-current',
});

export const DEFAULTS = Object.freeze({});

export const PART = defineParts('Navbar', {
    ROOT        : { class: 'navbar-root', aliases: ['root', 'nav'] },
    SECTION     : { class: 'navbar-section', aliases: ['section'] },
    ITEM        : { class: 'navbar-item', aliases: ['item', 'link'] },
    LABEL       : { class: 'navbar-label', aliases: ['label'] },
    DIVIDER     : { class: 'navbar-divider', aliases: ['divider'] },
    SPACER      : { class: 'navbar-spacer', aliases: ['spacer'] },
});

PART.ROOT.jit     = 'flex items-center gap-[var(--nb-gap)] px-[var(--nb-px)] h-[var(--nb-height)] bg-[var(--nb-bg)] [font-family:var(--nb-font-stack)]';
PART.SECTION.jit  = 'flex items-center gap-[var(--nb-section-gap)]';
PART.ITEM.jit     = `inline-flex items-center gap-[var(--nb-item-gap)] px-[var(--nb-item-px)] py-[var(--nb-item-py)] text-[var(--nb-item-font-size)] fg-[var(--nb-item-text)] rounded-[var(--nb-item-radius)] cursor-pointer ${TRANSITION_COLORS} hover:bg-[var(--nb-item-hover-bg)] {is-current}:bg-[var(--nb-item-active-bg)] {is-current}:fg-[var(--nb-item-active-text)] [text-decoration:none]`;
PART.LABEL.jit    = 'truncate';
PART.DIVIDER.jit  = 'w-[1px] self-stretch my-[var(--nb-divider-my)] bg-[var(--nb-divider-color)]';
PART.SPACER.jit   = 'flex-1';